const doc = $input.first().json;
let title = doc.title || 'Untitled';
let content = '';
let h1Found = false;
let keywords = [];
let publishStatus = 'draft';

if (doc.body && doc.body.content) {
  for (const element of doc.body.content) {
    if (!element.paragraph) continue;
    const para = element.paragraph;
    let text = '';
    for (const part of (para.elements || [])) {
      if (part.textRun) text += part.textRun.content || '';
    }
    text = text.replace(/\n+$/g, '').trim();
    if (!text) continue;

    if (text.startsWith('KEYWORDS:')) {
      keywords = text.replace('KEYWORDS:', '').split(',').map(k => k.trim()).filter(Boolean);
      continue;
    }
    if (text.startsWith('STATUS:')) {
      publishStatus = text.replace('STATUS:', '').trim().toLowerCase() || 'draft';
      continue;
    }

    const style = para.paragraphStyle?.namedStyleType || 'NORMAL_TEXT';
    if (style === 'HEADING_1') {
      if (!h1Found) {
        title = text;
        h1Found = true;
      }
      continue;
    }
    if (style === 'HEADING_2') {
      content += `<h2>${text}</h2>\n`;
      continue;
    }
    if (style === 'HEADING_3') {
      content += `<h3>${text}</h3>\n`;
      continue;
    }
    content += `<p>${text}</p>\n`;
  }
}

return {
  json: {
    title,
    content,
    keywords,
    publishStatus,
    docId: doc.documentId,
    docTitle: doc.title,
    sourceArticleUrl: 'https://www.dtapet.com/spc-flooring-complete-guide/',
    siteUrl: 'https://www.dtapet.com/',
    productCategoryUrl: 'https://www.dtapet.com/%D7%A4%D7%A8%D7%A7%D7%98-spc/',
    contactUrl: 'https://www.dtapet.com/%D7%99%D7%A6%D7%99%D7%A8%D7%AA-%D7%A7%D7%A9%D7%A8/',
    phoneNumber: '03-5235553',
    businessName: 'דויטשמן טפטים',
    businessDescription: 'טפטים, וילונות, חיפויים פולימריים ופרקט SPC בפתח תקווה',
    authorImageUrl: 'https://www.dtapet.com/wp-content/uploads/2022/09/logo-e1663485891304.png'
  }
};

const parsed = $node['Parse Document'].json;
let extracted = {};
try {
  const raw = $input.first().json;
  extracted = raw?.data?.extract || raw?.extract || {};
} catch (_) {
  extracted = {};
}

const siteData = {
  businessName: extracted.businessName || parsed.businessName,
  language: extracted.language || 'he',
  direction: extracted.direction || 'rtl',
  contactUrl: extracted.contactUrl || parsed.contactUrl,
  phoneNumber: extracted.phoneNumber || parsed.phoneNumber,
  logoUrl: extracted.logoUrl || parsed.authorImageUrl,
  hasStore: extracted.hasStore !== false,
  whatsappNumber: extracted.whatsappNumber || '',
  primaryColor: '#2b2e34',
  accentColor: '#bc1f1f',
  textColor: '#333333',
  backgroundColor: '#ffffff',
  borderColor: '#e5e5e5',
  fontFamily: "'Assistant', Arial, sans-serif"
};

return {
  json: {
    ...parsed,
    siteData,
    allowBackToTop: false,
    hasExistingFloatingButtons: true,
    shouldEmbedProducts: true
  }
};

const data = $input.first().json;
const haystack = `${data.title || ''} ${(data.keywords || []).join(' ')} ${data.content || ''}`.toLowerCase();
const shouldEmbedProducts = data.siteData.hasStore && (haystack.includes('spc') || haystack.includes('פרקט') || haystack.includes('ריצוף') || haystack.includes('floor'));
return { json: { ...data, shouldEmbedProducts } };

const data = $node['Detect Product Relevance'].json;
const raw = $input.first().json;
const extracted = raw?.data?.extract || raw?.extract || {};
const products = Array.isArray(extracted.products) ? extracted.products : [];

const normalizeImage = (value) => {
  if (!value) return '';
  return value.replace(/-\d+x\d+(?=\.(jpg|jpeg|png|webp)$)/i, '');
};

const selectedProducts = products
  .filter((product) => {
    const title = (product.title || '').trim();
    const url = (product.url || '').trim();
    const imageUrl = normalizeImage((product.imageUrl || '').trim());
    const availability = ((product.availability || '').trim()).toLowerCase();
    if (!title || !url || !imageUrl) return false;
    if (!url.includes('/shop/')) return false;
    if (availability.includes('אזל') || availability.includes('out of stock')) return false;
    return true;
  })
  .slice(0, 6)
  .map((product) => ({
    title: (product.title || '').trim(),
    url: (product.url || '').trim(),
    imageUrl: normalizeImage((product.imageUrl || '').trim()),
    price: (product.price || '').trim(),
    availability: (product.availability || '').trim()
  }));

return { json: { ...data, selectedProducts } };

const data = $node['Select Relevant Products'].json;
const response = $input.first().json;
const SUPABASE_URL = $env.SUPABASE_URL || '';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY || $env.SUPABASE_NEW_API_KEY || $env.SUPABASE_ANON_KEY || '';
const siteSlug = 'dtapet-com';

const normalizeImage = (value) => {
  if (!value) return '';
  return value.replace(/-\d+x\d+(?=\.(jpg|jpeg|png|webp)$)/i, '');
};

async function uploadImage(imageUrl, storagePath) {
  const normalized = normalizeImage(imageUrl);
  if (!normalized) return '';
  if (!SUPABASE_URL || !SUPABASE_KEY) return normalized;
  try {
    const imageResponse = await fetch(normalized);
    if (!imageResponse.ok) return normalized;
    const body = await imageResponse.arrayBuffer();
    const contentType = imageResponse.headers.get('content-type') || 'image/jpeg';
    const uploadResponse = await fetch(`${SUPABASE_URL}/storage/v1/object/article-assets/${storagePath}`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': contentType,
        'x-upsert': 'true'
      },
      body
    });
    if (!uploadResponse.ok) return normalized;
    return `${SUPABASE_URL}/storage/v1/object/public/article-assets/${storagePath}`;
  } catch (_) {
    return normalized;
  }
}

const rawItems = Array.isArray(response?.data) ? response.data : [];
const scrapedItems = rawItems.map((item) => item?.extract || {}).filter(Boolean);
const fallbackMap = new Map((data.selectedProducts || []).map((product) => [product.url, product]));
const normalizedProducts = [];

for (let index = 0; index < (data.selectedProducts || []).length; index += 1) {
  const fallback = data.selectedProducts[index] || {};
  const scraped = scrapedItems.find((item) => item.productUrl === fallback.url) || {};
  const title = (scraped.productTitle || fallback.title || '').trim();
  const url = (scraped.productUrl || fallback.url || '').trim();
  const imageUrl = normalizeImage((scraped.productImage || fallback.imageUrl || '').trim());
  const availability = (scraped.availability || fallback.availability || '').trim().toLowerCase();
  if (!title || !url || !imageUrl) continue;
  if (availability.includes('אזל') || availability.includes('out of stock')) continue;
  const slug = title.toLowerCase().replace(/[^a-z0-9֐-׿]+/g, '-').replace(/^-+|-+$/g, '') || `product-${index + 1}`;
  const stableImageUrl = await uploadImage(imageUrl, `${siteSlug}/products/${slug}.jpg`);
  normalizedProducts.push({
    title,
    url,
    imageUrl: stableImageUrl || imageUrl,
    price: (scraped.productPrice || fallback.price || '').trim(),
    description: (scraped.productDescription || '').trim(),
    availability
  });
}

let stableLogoUrl = data.siteData.logoUrl || data.authorImageUrl || '';
if (stableLogoUrl) {
  stableLogoUrl = await uploadImage(stableLogoUrl, `${siteSlug}/branding/logo.png`);
}

return {
  json: {
    ...data,
    products: normalizedProducts,
    authorImageUrl: stableLogoUrl || data.authorImageUrl || data.siteData.logoUrl || '',
    assetStabilizationEnabled: !!SUPABASE_URL && !!SUPABASE_KEY
  }
};

const data = $node['Detect Product Relevance'].json;
return {
  json: {
    ...data,
    products: [],
    assetStabilizationEnabled: false
  }
};

const improved = $input.first().json;
const original = $node['Merge Product Data'].json;
let html = improved.improved_html || improved.html || '';

html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
html = html.replace(/\sclass="[^"]*"/g, '');
html = html.replace(/<!--[\s\S]*?-->/g, '');
html = html.replace(/<script[^>]*application\/ld\+json[^>]*>[\s\S]*?<\/script>/gi, '');
html = html.replace(/```[\s\S]*?```/g, '');
html = html.replace(/<(?:span|p|div)[^>]*>\s*(?:נכתב בתאריך|עודכן לאחרונה)[^<]*<\/(?:span|p|div)>/gi, '');
html = html.replace(/<(?:span|p|div)[^>]*>\s*(?:\d{1,2}\/\d{1,2}\/\d{4}|\d{1,2} [A-Za-z]+ \d{4})\s*<\/(?:span|p|div)>/gi, '');
html = html.trim();
if (!html.startsWith('<article')) {
  html = `<article lang="he" dir="rtl">${html}</article>`;
}
html = html.replace(/>\s+</g, '><');

return {
  json: {
    title: original.title,
    content: html,
    excerpt: improved.meta_description || '',
    seoScore: improved.seo_score || 0,
    publishStatus: original.publishStatus || 'draft',
    sourceArticleUrl: original.sourceArticleUrl,
    htmlFileName: 'Improved_HTML_Template.html'
  }
};

const item = $input.first();
const html = item.json.content || '';
return {
  json: { ...item.json },
  binary: {
    articleHtml: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: item.json.htmlFileName || 'Improved_HTML_Template.html'
    }
  }
};
